mapper.select:
SELECT cp.*, m.major_name AS majorName, am.major_name AS admissionMajorName, a.real_name AS operatorName, s.school_name AS schoolName FROM candidate_push cp LEFT JOIN major m ON cp.major_id = m.major_id LEFT JOIN major am ON cp.admission_major_id = am.major_id LEFT JOIN account a ON cp.operator_id = a.account_id LEFT JOIN school s ON cp.school_id = s.school_id WHERE 1=1
AND cp.school_id = #{schoolId}
AND cp.status IN
#{s}
AND cp.total_score >= #{minScore}
AND cp.total_score <= #{maxScore}
AND cp.intention ILIKE '%' || #{intentionKeyword} || '%'
AND cp.nationality = #{nationality}
AND cp.pushed_at >= #{pushTimeStart}
AND cp.pushed_at <= #{pushTimeEnd}
AND (cp.major_id = #{majorId} OR cp.admission_major_id = #{majorId})
AND cp.push_round = #{round}
ORDER BY cp.total_score ORDER BY cp.condition_deadline ORDER BY cp.pushed_at
ASC DESC

SELECT * FROM candidate_push
WHERE status = 'CONDITIONAL'
  AND condition_deadline <= #{now}

SELECT * FROM candidate_push
WHERE status = 'INVITED'
  AND invitation_expires_at <= #{now}

SELECT DISTINCT yr FROM (
    SELECT EXTRACT(YEAR FROM pushed_at)::int AS yr FROM candidate_push WHERE deleted = 0

        AND school_id = #{schoolId}

    UNION
    SELECT EXTRACT(YEAR FROM operated_at)::int AS yr FROM candidate_push WHERE deleted = 0 AND operated_at IS NOT NULL

        AND school_id = #{schoolId}

) years
WHERE yr IS NOT NULL AND yr > 0
ORDER BY yr DESC

SELECT cp.*,
       s.school_name       AS schoolName,
       am.major_name       AS admissionMajorName
FROM candidate_push cp
LEFT JOIN school s  ON cp.school_id = s.school_id
LEFT JOIN major am  ON cp.admission_major_id = am.major_id
WHERE 1=1

    AND cp.school_id = #{schoolId}


    AND cp.status IN

        #{s}



    AND cp.total_score >= #{minScore}


    AND cp.total_score <= #{maxScore}


    AND cp.intention ILIKE '%' || #{intentionKeyword} || '%'


    AND cp.nationality = #{nationality}


    AND cp.pushed_at >= #{pushTimeStart}


    AND cp.pushed_at <= #{pushTimeEnd}


    AND (cp.major_id = #{majorId} OR cp.admission_major_id = #{majorId})


    AND cp.push_round = #{round}

ORDER BY cp.pushed_at DESC
LIMIT 5000
